import{_ as e,o,c as r,a2 as i}from"./chunks/framework.DnrXFDHb.js";const s=JSON.parse('{"title":"G10: 關鍵合作夥伴與Tier1客戶 - 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/3189_景碩/20260423/G10_關鍵合作夥伴與Tier1客戶_投資研究員.md","filePath":"審計報告庫/經營審計/3189_景碩/20260423/G10_關鍵合作夥伴與Tier1客戶_投資研究員.md"}'),t={name:"審計報告庫/經營審計/3189_景碩/20260423/G10_關鍵合作夥伴與Tier1客戶_投資研究員.md"};function l(d,a,c,n,_,h){return o(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="g10-關鍵合作夥伴與tier1客戶-投資研究員-審計報告" tabindex="-1">G10: 關鍵合作夥伴與Tier1客戶 - 投資研究員 審計報告 <a class="header-anchor" href="#g10-關鍵合作夥伴與tier1客戶-投資研究員-審計報告" aria-label="Permalink to &quot;G10: 關鍵合作夥伴與Tier1客戶 - 投資研究員 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>公司是否擁有具備國際指標性的關鍵合作夥伴或 Tier1 客戶？這類關係的穩定度與進入壁壘為何？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>景碩的關鍵合作夥伴以全球Tier 1半導體設計公司為主：NVIDIA（ABF CPU載板、H100/B200供應鏈）、AMD（Xilinx FPGA載板+GPU載板）、Qualcomm（車用Snapdragon Cockpit）、Broadcom（網通ASIC）、Google（TPU v6 ABF載板）。BT載板客戶涵蓋Micron（DDR5）、MediaTek、TI。供應端合作夥伴：日本味之素（ABF膜關鍵原料獨家供應商）、長春化工（BT樹脂）。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>B（持平）。客戶質量頂級（Tier 1半導體公司），但前五大客戶集中度&gt;70%為結構性風險。供應鏈關鍵依賴日本味之素的ABF膜、該原料面臨供應受限（載板產業共同困境）。2025年NVIDIA單一客戶佔營收約25-30%，任何供應鏈分散決定都將直接影響營收。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p>客戶集中度詳細分佈（2025年法說會推估）：NVIDIA佔25-30%（核心成長動能）、Broadcom 10-15%（網通+ASIC）、AMD/Xilinx 8-12%（FPGA+GPU）、Qualcomm 8-10%（車用+手機）、Google 5-8%（TPU目前量產初期）、Micron+TI+MediaTek及其他約25-30%。單一最大客戶NVIDIA佔比超過四分之一，若發生供應鏈分散（如NVIDIA將部分訂單轉給Ibiden或欣興），將對營收造成顯著衝擊。</p><p>供應鏈分析：ABF載板關鍵材料ABF膜由日本味之素獨佔供應（全球市佔率95%+），供應量限制是ABF載板擴產的關鍵瓶頸。味之素2025年仍未大幅擴產，僅靠良率提升和製程優化做到小幅增長（約5-8%）。長春化工（台灣）提供BT樹脂，替代性較高。銅箔由日商三井金屬供應，穩定無虞。</p><p>客戶議價力分析：NVIDIA等大客戶有極強議價權（單一訂單規模可達50億+），每年要求3% cost-down。景碩的應對策略是透過產品升級（高層數ABF載板）維持ASP，同時增加ASIC客戶分散NVIDIA佔比。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p>景碩的客戶/供應商結構代表典型的「台灣半導體中間層困境」——上游關鍵材料被日系壟斷，下游被美國AI巨頭壓價，利潤空間受雙向擠壓。客戶集中度&gt;70%的結構目前因AI需求爆炸而不構成即時風險，但任何一家主力客戶的供應鏈決策變動（如NVIDIA分散供貨、Broadcom自研載板）都將直接影響營收。</p><p>供應鏈端的ABF膜瓶頸是行業性問題（非景碩獨有），值得注意的變化是：若味之素在2027年前仍未擴產，ABF載板全球產能擴張將受硬限制，可能導致載板持續漲價（有利於現有廠商）。</p><p>最需關注的供應鏈風險事件：味之素ABF膜擴產決策（2026年底前需宣布新廠計劃），若延遲至2027年後，全球ABF載板供需缺口可能從預估的10%擴至15%+，出現供給更緊張但產能無法擴張的困境。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><code>法說會</code>: 景碩2026年3月法說會客戶結構</li><li><code>經濟日報</code>: NVIDIA GPU載板供應鏈分析（2025年）</li><li><code>優分析UAnalyze</code>: 前五大客戶佔比推估（&gt;70%）</li><li><code>IEK產業情報網</code>: ABF膜材料供應鏈瓶頸分析（味之素獨佔）</li><li><code>日經新聞</code>: 味之素ABF膜產能規劃報導（2025年未大幅擴產）</li></ul>',17)])])}const p=e(t,[["render",l]]);export{s as __pageData,p as default};
